      })),
      payments: saleDetails.map((item) => ({
        saleDetailId: item.saleDetailId ?? item.sale_detail_id ?? null,
        requestTypeId: item.requestTypeId ?? item.request_type_id ?? null,
        requestDetailId: item.requestDetailId ?? item.request_detail_id ?? null,
        totalPrice: number(item.totalPrice ?? item.total_price),
        saleDate: item.saleDate ?? item.sale_date ?? null,
        receiptPaymentDate: item.receiptPaymentDate ?? item.receipt_payment_date ?? null,
        paymentMethodId: item.paymentMethodId ?? item.payment_method_id ?? null,
        isConfirmed: item.isConfirmed ?? item.is_confirmed ?? null,
        summary: item.summary ?? null,
      })),
      requestDetails,
      saleDetails,
    },
    sources: [
      { type: 'api', name: 'GET /request-details' },
      { type: 'api', name: 'GET /sale-details' },
    ],
  },
}]
